import sqlite3

def get_order(user_id, order_id):
    conn = sqlite3.connect("orders.db")
    cursor = conn.cursor()
    query = "SELECT * FROM orders WHERE user_id=? AND order_id=?"
    cursor.execute(query, (user_id, order_id))
    result = cursor.fetchone()
    if result:
        return {
            "order_id": result[0],
            "user_id": result[1],
            "product_name": result[2],
            "quantity": result[3],
            "price": result[4]
        }
    else:
        return None